def parse_roman(s: str) -> int | None:
    if not s or any(c not in 'IVXLCDM' for c in s) or s != s.upper():
        return None
    roman_values = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    total = 0
    prev_value = 0
    count = 1
    for i in range(len(s)):
        value = roman_values[s[i]]
        if count > 3:
            return None
        if value > prev_value:
            if (prev_value == 1 and s[i-1] not in 'IX') or 
               (prev_value == 10 and s[i-1] not in 'XL') or 
               (prev_value == 100 and s[i-1] not in 'CD'):
                return None
            total += value - 2 * prev_value
            count = 1
        else:
            if value == prev_value:
                count += 1
                if count > 3:
                    return None
            else:
                count = 1
        total += value
        prev_value = value
    return total if 1 <= total <= 3999 else None

import re

def parse_csv_row(line: str) -> list[str]:
    pattern = r'(?:[^,"]|"(?:[^"]|"")*")+'  # Match unquoted or quoted fields
    return re.findall(pattern, line)

