def parse_roman(s: str) -> int | None:
    if not s or any(c not in 'IVXLCDM' for c in s) or any(s.count(c) > 3 for c in 'IXC') or s.count('V') > 1 or s.count('L') > 1 or s.count('D') > 1 or 'IIII' in s or 'VV' in s or 'IL' in s or 'VX' in s or 'VL' in s or 'IC' in s or 'ID' in s or 'IL' in s or 'XD' in s or 'XM' in s or 'LC' in s or 'LD' in s or 'DM' in s:
        return None
    roman_values = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    total = 0
    prev_value = 0

    for char in reversed(s):
        value = roman_values[char]
        if value < prev_value:
            total -= value
        else:
            total += value
        prev_value = value

    if total < 1 or total > 3999:
        return None
    return total
